1	/* ---------------------------------------------------------------------------
2	 * primitives.css — suite 13/P05
3	 * Shared styles for the five reusable primitives: Button, Link, Surface,
4	 * Card, Badge. Tokens-only — no project-specific copy or layout.
5	 * --------------------------------------------------------------------------- */
6	
7	/* ---------- Button ---------- */
8	.p-btn {
9	  font-family: var(--t-mono);
10	  font-size: var(--t-base-size);
11	  line-height: var(--t-base-lh);
12	  letter-spacing: var(--t-normal);
13	  display: inline-flex;
14	  align-items: center;
15	  justify-content: center;
16	  gap: var(--s-2);
17	  padding: var(--s-2) var(--s-4);
18	  border: 1px solid var(--line);
19	  background-color: transparent;
20	  color: var(--fg);
21	  cursor: pointer;
22	  transition: background-color var(--d-tap) var(--ease-out),
23	    border-color var(--d-fast) var(--ease-out),
24	    color var(--d-fast) var(--ease-out);
25	  border-radius: var(--r-1);
26	}
27	
28	.p-btn:focus-visible {
29	  outline: 2px solid var(--accent);
30	  outline-offset: 2px;
31	}
32	
33	.p-btn[disabled],
34	.p-btn[aria-disabled="true"] {
35	  cursor: not-allowed;
36	  opacity: 0.6;
37	}
38	
39	/* size */
40	.p-btn--sm {
41	  font-size: var(--t-sm-size);
42	  line-height: var(--t-sm-lh);
43	  padding: var(--s-1) var(--s-3);
44	}
45	.p-btn--md {
46	  font-size: var(--t-base-size);
47	  line-height: var(--t-base-lh);
48	  padding: var(--s-2) var(--s-4);
49	}
50	.p-btn--lg {
51	  font-size: var(--t-md-size);
52	  line-height: var(--t-md-lh);
53	  padding: var(--s-3) var(--s-5);
54	}
55	
56	/* variant */
57	.p-btn--solid {
58	  background-color: var(--fg);
59	  color: var(--fg-inverse);
60	  border-color: var(--fg);
61	}
62	.p-btn--solid:hover:not([disabled]) {
63	  background-color: var(--fg-mute);
64	  border-color: var(--fg-mute);
65	}
66	.p-btn--outline {
67	  background-color: transparent;
68	  border-color: var(--line-strong);
69	  color: var(--fg);
70	}
71	.p-btn--outline:hover:not([disabled]) {
72	  background-color: var(--bg-mute);
73	}
74	.p-btn--ghost {
75	  background-color: transparent;
76	  border-color: transparent;
77	  color: var(--fg);
78	}
79	.p-btn--ghost:hover:not([disabled]) {
80	  background-color: var(--bg-mute);
81	}
82	
83	/* tone */
84	.p-btn--accent.p-btn--solid {
85	  background-color: var(--accent);
86	  border-color: var(--accent);
87	  color: var(--accent-fg);
88	}
89	.p-btn--accent.p-btn--solid:hover:not([disabled]) {
90	  background-color: var(--accent);
