/* ---------------------------------------------------------------------------
 * prose.css — suite 16/P03
 * Body composition primitives: Prose, Anchor, Aside.
 * Builds on .t-prose from typography.css; resets default browser styles
 * for elements nested inside .p-prose so long-form bodies render with
 * even rhythm and the two-face type system (mono headings, serif body).
 * --------------------------------------------------------------------------- */

/* ---------- Prose ---------- */
.p-prose {
  font-family: var(--t-serif);
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
  letter-spacing: var(--t-normal);
  max-width: 64ch;
  color: var(--fg);
}

.p-prose > * + * {
  margin-top: var(--s-4);
}

.p-prose p {
  margin: 0;
  font-family: var(--t-serif);
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
}

.p-prose h2,
.p-prose h3 {
  font-family: var(--t-mono);
  letter-spacing: var(--t-tight);
  font-weight: 600;
  margin: 0;
}

.p-prose h2 {
  font-size: var(--t-xl-size);
  line-height: var(--t-xl-lh);
}

.p-prose h3 {
  font-size: var(--t-lg-size);
  line-height: var(--t-lg-lh);
}

.p-prose > h2,
.p-prose > h3 {
  margin-top: var(--s-6);
}

.p-prose ul,
.p-prose ol {
  margin: 0;
  padding-left: var(--s-5);
  font-family: var(--t-serif);
}

.p-prose ul {
  list-style: disc;
}

.p-prose ol {
  list-style: decimal;
}

.p-prose li + li {
  margin-top: var(--s-2);
}

.p-prose a {
  color: var(--fg);
  text-decoration: underline;
  text-underline-offset: 2px;
  text-decoration-thickness: 1px;
  transition: color var(--d-fast) var(--ease-out);
}

.p-prose a:hover {
  color: var(--accent);
}

.p-prose a:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.p-prose code {
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  background: var(--bg-mute);
  padding: 0 4px;
  border-radius: var(--r-1);
}

/* ---------- Anchor ---------- */
.p-anchor {
  display: flex;
  align-items: baseline;
  gap: var(--s-2);
  font-family: var(--t-mono);
  font-size: var(--t-xl-size);
  line-height: var(--t-xl-lh);
  letter-spacing: var(--t-tight);
  font-weight: 600;
  margin: 0;
  scroll-margin-top: var(--s-7);
}

.p-anchor__sigil {
  color: var(--fg-mute);
  font-family: var(--t-mono);
}

.p-anchor__label {
  flex: 0 1 auto;
}

.p-anchor__copy {
  appearance: none;
  background: transparent;
  border: 0;
  padding: 0;
  cursor: pointer;
  font-family: var(--t-mono);
  font-size: var(--t-md-size);
  line-height: 1;
  color: var(--fg-faint);
  opacity: 0;
  transition: opacity var(--d-fast) var(--ease-out),
    color var(--d-fast) var(--ease-out);
}

.p-anchor:hover .p-anchor__copy,
.p-anchor:focus-within .p-anchor__copy {
  opacity: 1;
}

.p-anchor__copy:hover,
.p-anchor__copy:focus-visible {
  color: var(--accent);
  opacity: 1;
}

.p-anchor__copy:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

/* ---------- Aside ---------- */
.p-aside {
  display: block;
}

.p-aside__label {
  font-family: var(--t-mono);
  font-size: var(--t-sm-size);
  line-height: var(--t-sm-lh);
  letter-spacing: var(--t-wide);
  text-transform: uppercase;
  color: var(--fg-mute);
  margin-bottom: var(--s-3);
}

.p-aside__label[data-tone="warn"] {
  color: var(--warn);
}

.p-aside__label[data-tone="voice"] {
  color: var(--accent);
}

.p-aside__body {
  font-family: var(--t-serif);
  font-size: var(--t-base-size);
  line-height: var(--t-base-lh);
}

.p-aside--voice .p-aside__body {
  font-family: var(--t-serif);
  font-size: var(--t-sm-size);
  line-height: var(--t-base-lh);
  font-style: italic;
}

/* aside spacing inside Prose: keep rhythm consistent */
.p-prose > .p-aside {
  margin-top: var(--s-5);
  margin-bottom: var(--s-5);
}

