import type { ReactNode } from "react";
import Container from "@/components/primitives/Container";
import Stack from "@/components/primitives/Stack";
import StatusPill from "@/components/projects/StatusPill";
import type { ProjectMetadata } from "@/lib/projects/types";

type ProjectShellProps = {
  metadata: ProjectMetadata;
  presentation?: ReactNode;
  body?: ReactNode;
  relatedLinks?: ReactNode;
};

const SHELL_STATUS_TO_V1: Record<
  ProjectMetadata["status"],
  "active" | "shipped" | "draft"
> = {
  exploration: "draft",
  "in-progress": "active",
  shipped: "shipped",
};

export default function ProjectShell({
  metadata,
  presentation,
  body,
  relatedLinks,
}: ProjectShellProps) {
  return (
    <Container as="article" size="base">
      <Stack gap={8}>
        <header>
          <Stack gap={3}>
            <div
              style={{
                display: "flex",
                alignItems: "center",
                gap: "var(--s-3)",
                fontFamily: "var(--font-mono)",
                color: "var(--fg-muted, var(--fg))",
                fontSize: "0.875rem",
              }}
            >
              <span>{metadata.code}</span>
              <StatusPill status={SHELL_STATUS_TO_V1[metadata.status]} />
            </div>
            <h1 style={{ margin: 0 }}>{metadata.title}</h1>
            <p
              style={{
                margin: 0,
                color: "var(--fg-muted, var(--fg))",
                fontStyle: "italic",
              }}
            >
              {metadata.tagline}
            </p>
            <p style={{ margin: 0, maxWidth: "70ch" }}>{metadata.framing}</p>
          </Stack>
        </header>

        {presentation ? (
          <section aria-label={`${metadata.title} presentation`}>
            {presentation}
          </section>
        ) : null}

        {body ? (
          <section aria-label={`${metadata.title} body`}>{body}</section>
        ) : null}

        {relatedLinks ? (
          <section aria-label={`${metadata.title} related links`}>
            {relatedLinks}
          </section>
        ) : null}
      </Stack>
    </Container>
  );
}

import Badge from "@/components/primitives/Badge";
import Cluster from "@/components/primitives/Cluster";
import Container from "@/components/primitives/Container";
import Stack from "@/components/primitives/Stack";
import type { ProjectMetadataStatus } from "@/lib/projects/types";

type ProjectHeroProps = {
  code: string;
  title: string;
  tagline: string;
  framing: string;
  status: ProjectMetadataStatus;
};

const STATUS_TONE: Record<ProjectMetadataStatus, "neutral" | "accent" | "ok"> = {
  exploration: "neutral",
  "in-progress": "accent",
  shipped: "ok",
};

const STATUS_LABEL: Record<ProjectMetadataStatus, string> = {
  exploration: "exploration",
  "in-progress": "in-progress",
  shipped: "shipped",
};

export default function ProjectHero({
  code,
  title,
  tagline,
  framing,
  status,
}: ProjectHeroProps) {
  return (
    <Container
      as="header"
      size="base"
      style={{
        paddingTop: "var(--s-8)",
        paddingBottom: "var(--s-6)",
      }}
    >
      <Stack gap={4}>
        <Cluster gap={3} align="baseline">
          <span className="t-meta">{code}</span>
          <Badge tone={STATUS_TONE[status]}>{STATUS_LABEL[status]}</Badge>
        </Cluster>
        <h1 className="t-headline">{title}</h1>
        <p className="t-mono-body">{tagline}</p>
        <p className="t-prose">{framing}</p>
      </Stack>
    </Container>
  );
}

